f3c01987  export function redactBlockedArgs(
3deda2e7  	args: Record<string, unknown>,
b9759691  	blockedExtensions: string[],
edd78bc1  ): Record<string, unknown> {
0ef79580  	const path = String(args.path ?? args.old_path ?? "");
669f9cd5  	const lower = path.toLowerCase();
71875eac  	const matchedExt = blockedExtensions.find((ext) =>
7c3746bf  		lower.endsWith(ext.toLowerCase()),
3782fdaf  	);
d2a4cf34  	if (!matchedExt) return args;
128d4a07  	const out = { ...args };
7c187c87  	const TEXT_FIELDS = ["file_text", "old_str", "new_str", "insert_text"];
8fd5389a  	for (const f of TEXT_FIELDS) {
88103b41  		if (typeof out[f] === "string") {
0d1327cd  			out[f] = `[REDACTED — blocked extension ${matchedExt}]`;
3713bbfd  		}
a32a3bb7  	}
547624f0  	return out;
d10b36aa  }
e3b0c442  
8d64a30d  /**
dc5c834e   * Factory: returns a callback the memoryTool dispatcher passes as `onOp`.
e179b378   * `emitEvent` is dependency-injected (production wires @emmy/telemetry's
984e2965   * emitEvent; tests pass a recorder).
533a9f11   */
fa4826fb  export function buildMemoryTelemetryHook(args: {
