73c8766d  		event: string;
5a2fb44d  		ts: string;
51a9c555  		[k: string]: unknown;
d8d824e6  	}) => void;
74096c3f  	counters?: MemoryTelemetryCounters;
75805d25  	argsForOp?: () => Record<string, unknown>;
4d814252  	blockedExtensions: string[];
