96382143  	return (event) => {
96f9d151  		args.counters?.record(event);
4a0d427d  		const rec: Record<string, unknown> = {
915f2c10  			event: "memory.op",
64b70a1b  			ts: new Date().toISOString(),
2612c509  			"gen_ai.tool.name": "memory",
06f2bbcf  			"emmy.memory.command": event.command,
c8a97f50  			"emmy.memory.scope": event.scope,
940e466a  			"emmy.memory.path": event.path,
