a2c23396  //
abd9de06  // Phase 3 Plan 03-02 Task 3 (GREEN) — OTel SDK initialization.
a2c23396  //
e0cd3b53  // Verbatim-adapted from RESEARCH §Ex 2 (lines 722-777):
560bc589  //   - @opentelemetry/sdk-node's NodeSDK with resource {service.name: "emmy"}
174c937b  //   - BatchSpanProcessor(OTLPTraceExporter) as the export-bound processor
865b391d  //   - EmmyProfileStampProcessor as the FIRST processor in the pipeline so
95a4f554  //     onStart stamping runs before any exporter sees the span
050c4591  //   - Langfuse OTLP endpoint at http://127.0.0.1:3000/api/public/otel/v1/traces
52a8d5cf  //   - Auth: Basic base64(pk:sk) + x-langfuse-ingestion-version: 4
bf9b9233  //     (langfuse.com/integrations/native/opentelemetry, verified 2026-04-21)
a2c23396  //
ee69305b  // Kill-switch (D-08 + T-03-02-05 accept):
d7f952a2  //   - EMMY_TELEMETRY=off -> resolveTelemetryEnabled returns false
c83d89ba  //   - --no-telemetry in argv -> resolveTelemetryEnabled returns false
10846c7e  //   - Passing {enabled: false} to initOtel returns null and logs
7253c7ca  //     "OBSERVABILITY: OFF" to stderr
a2c23396  //
1baa0fb7  // Loopback reachability probe (D-06 boot banner differentiation):
cfd8984e  //   After sdk.start(), we do a HEAD probe against langfuseBaseUrl with a
e7eec172  //   2-second AbortSignal.timeout. Success -> "OBSERVABILITY: ON - JSONL +
b364da27  //   Langfuse OTLP (Langfuse responded <status>)". Failure -> "OBSERVABILITY:
59d0ef31  //   JSONL-only (Langfuse unreachable at <url>)". The SDK itself keeps trying
17493d48  //   to export on BatchSpanProcessor's schedule; the probe is purely for the
8a1a4e01  //   boot banner.
e3b0c442  
237f366e  import { NodeSDK } from "@opentelemetry/sdk-node";
be9483f0  import { OTLPTraceExporter } from "@opentelemetry/exporter-trace-otlp-http";
ed18353c  import { BatchSpanProcessor } from "@opentelemetry/sdk-trace-base";
77153751  import { resourceFromAttributes } from "@opentelemetry/resources";
ce43ac1e  import { ATTR_SERVICE_NAME } from "@opentelemetry/semantic-conventions";
e3b0c442  
9149623d  import { EmmyProfileStampProcessor } from "./profile-stamp-processor";
e3b0c442  
1ccf37c1  export interface InitOtelOpts {
cb5f1448  	langfusePublicKey: string;
2cfdb9ae  	langfuseSecretKey: string;
2f728e26  	profile: { id: string; version: string; hash: string };
2ebdae23  	enabled: boolean;
337164c9  	/** Default: http://127.0.0.1:3000 (loopback, T-03-02-02 mitigation). */
c2c49944  	langfuseBaseUrl?: string;
d10b36aa  }
e3b0c442  
8d64a30d  /**
b6b3e675   * Resolve telemetry-enabled flag from process env + argv. Pure function; no
812ad8bf   * IO. Called at pi-emmy.ts boot before initOtel.
533a9f11   */
39b8446c  export function resolveTelemetryEnabled(opts: {
9905a0d3  	env: Record<string, string | undefined>;
2e3f1217  	argv: string[];
9337bcc4  }): boolean {
676a599e  	if (opts.env.EMMY_TELEMETRY === "off") return false;
b89b2f71  	if (opts.argv.includes("--no-telemetry")) return false;
d192f8fa  	return true;
d10b36aa  }
e3b0c442  
8d64a30d  /**
437c02b6   * Initialize the OTel NodeSDK with a Langfuse OTLP trace exporter plus the
7c82d188   * EmmyProfileStampProcessor. Returns the SDK handle (pass to shutdownOtel at
9962843f   * process exit), or null if telemetry is disabled.
64e75266   *
4477face   * Callers: pi-emmy.ts runs this AFTER parseCliArgs + loadProfile (which MUST
af53554f   * remain emitEvent-free — guarded by profile-loader-no-telemetry.test.ts) and
e24e2e56   * BEFORE createEmmySession, so every span emitted downstream has a live SDK
39853278   * installed globally.
533a9f11   */
522890e5  export async function initOtel(opts: InitOtelOpts): Promise<NodeSDK | null> {
33da8f1a  	if (!opts.enabled) {
f5a89d07  		console.error("[emmy] OBSERVABILITY: OFF (EMMY_TELEMETRY=off or --no-telemetry)");
564bbf24  		return null;
a32a3bb7  	}
d606e3e1  	const baseUrl = opts.langfuseBaseUrl ?? "http://127.0.0.1:3000";
064e8d1d  	const auth = Buffer.from(`${opts.langfusePublicKey}:${opts.langfuseSecretKey}`).toString("base64");
d9c5fda4  	const exporter = new OTLPTraceExporter({
84ed11e1  		url: `${baseUrl}/api/public/otel/v1/traces`,
161d404f  		headers: {
32c5a742  			Authorization: `Basic ${auth}`,
24c30493  			"x-langfuse-ingestion-version": "4",
b7fa8888  		},
eeb33785  	});
c657b753  	const sdk = new NodeSDK({
4dc328ce  		resource: resourceFromAttributes({
b9c40c40  			[ATTR_SERVICE_NAME]: "emmy",
6ec9b6b2  			// OTel GenAI semconv — canonical constant name across spans that
db6c79f3  			// describe LLM interactions. Literal string (rather than importing
d5567cc1  			// from /incubating) to keep this module compatible with semconv
56042454  			// releases where the incubating surface moves around.
10e771d2  			"gen_ai.system": "vllm",
eaef3a8c  		}),
c8de3bd0  		spanProcessors: [
b0130bf9  			new EmmyProfileStampProcessor(opts.profile),
1a6d9fa7  			new BatchSpanProcessor(exporter),
dd11dec9  		],
eeb33785  	});
95551eb1  	sdk.start();
e3b0c442  
73e208d8  	// Langfuse reachability probe — purely for boot-banner text; the SDK keeps
e4868a69  	// trying on its own schedule regardless of this result.
debaf31e  	try {
bc4699db  		const r = await fetch(baseUrl, {
45e40d12  			method: "HEAD",
51acfb03  			signal: AbortSignal.timeout(2000),
206aa438  		});
5b955659  		console.error(
3e9a1e98  			`[emmy] OBSERVABILITY: ON - JSONL + Langfuse OTLP (Langfuse responded ${r.status})`,
80e5ba03  		);
caf79c21  	} catch {
a3f1fab2  		console.error(`[emmy] OBSERVABILITY: JSONL-only (Langfuse unreachable at ${baseUrl})`);
a32a3bb7  	}
161bd58e  	return sdk;
d10b36aa  }
e3b0c442  
8d64a30d  /**
7af83f82   * Flush and shut down the OTel NodeSDK. Idempotent on null input so callers
74f46590   * can pass the return value of initOtel (which may be null when telemetry is
2cf9c20e   * disabled) without a guard.
533a9f11   */
5f16df90  export async function shutdownOtel(sdk: NodeSDK | null): Promise<void> {
6ace3f96  	if (sdk) await sdk.shutdown();
d10b36aa  }
