73e208d8  	// Langfuse reachability probe — purely for boot-banner text; the SDK keeps
e4868a69  	// trying on its own schedule regardless of this result.
debaf31e  	try {
bc4699db  		const r = await fetch(baseUrl, {
45e40d12  			method: "HEAD",
51acfb03  			signal: AbortSignal.timeout(2000),
206aa438  		});
